sp_widget.client_script:
api.controller=function($rootScope, $scope, $timeout, $sce, spUtil, $log, $location) {
  /* widget controller */
  var c = this;
	var dtech_tasker_common = x_153465_discovert.dtech_tasker_common;
	var shared = {};

	$scope.tasker_left_navigation_widget = undefined;
	$scope.tasker_app_header_widget = undefined;
	c.data.tasker_app_body_widget = undefined;
	$scope.leftNavigationWidth = undefined;


	main();
	function main(){
		c.data.submitting=true;
		// NOTE: may want to put into UI Script
		c.data.appContext=dtech_tasker_common.getContext(c.data.table);
		loadLeftNavigation();
		loadAppHeader();
		loadAppBody();
		c.data.submitting = false;
	}

	$scope.changeAppContext = function(context){
		c.data.appContext=context;
		if(c.data.tasker_app_headers.length){
			c.data.tasker_app_headers[0].changeAppContext(context);
		}
		if(c.data.tasker_app_bodies.length){
			c.data.tasker_app_bodies[0].changeAppContext(context);
		}		
	};

	$scope.toggleLeftNavigation = function(){
		_toggleLeftNavigation();
	}
/*	
	$scope.$watch('$viewContentLoaded', function(){
		if(!$scope.leftNavigationWidth){
			$scope.toggleLeftNavigation();
		}
	});
*/
	function _toggleLeftNavigation(){
		if(c.data.tasker_app_body_widget){
			var leftPanelDiv = angular.element(document.getElementById('tasker_app_left_navigation'))[0];
			$scope.leftNavigationWidth=leftPanelDiv.clientWidth;
			c.data.tasker_app_body_widget.toggleNavigationWidth(leftPanelDiv.clientWidth);
		}
	}

	function loadLeftNavigation(){
		var tasker_left_navigation_wp = {
			// not sure if we need any params
			table: c.data.table,
			sys_id: c.data.sys_id,
			appContext: c.data.appContext,
			appPreferences: c.data.appPreferences,
			shared: shared
		};
		c.data.tasker_left_navigations = [];

		spUtil.get('tasker_left_navigation', tasker_left_navigation_wp).then(function(response){
			$scope.tasker_left_navigation_widget = response;
			c.data.tasker_left_navigations.push($scope.tasker_left_navigation_widget);
		});
	}	

	function loadAppHeader(){
		var tasker_app_header_wp = {
			appContext: c.data.appContext,			
			table: c.data.table,
			sys_id: c.data.sys_id,
			// not sure if we need any params
			shared: shared
		};
		c.data.tasker_app_headers = [];

		spUtil.get('tasker_app_header_container', tasker_app_header_wp).then(function(response){
			$scope.tasker_app_header_widget = response;
			c.data.tasker_app_headers.push($scope.tasker_app_header_widget);
		});
	}

	function loadAppBody(){
		var tasker_app_body_wp = {
			// not sure if we need any params
			appContext: c.data.appContext,
			appPreferences: c.data.appPreferences,
			leftNavigationWidth: $scope.leftNavigationWidth,
			table: c.data.table,
			sys_id: c.data.sys_id,
			shared: shared
		};
		c.data.tasker_app_bodies = [];

		spUtil.get('tasker_app_body_container', tasker_app_body_wp).then(function(response){
			c.data.tasker_app_body_widget =response;
			c.data.tasker_app_bodies.push(c.data.tasker_app_body_widget);
			_toggleLeftNavigation();
		});
	}
};

