// WIDGET BASE: Tasker App Widget
// COMPANY: Discover Technologies
(function() {
	main();

	function main(){
		data.table = (input || {}).table || (options || {}).table || $sp.getParameter("table") || "";
		data.sys_id = (input || {}).sys_id || (options || {}).sys_id || $sp.getParameter("sys_id") || $sp.getParameter("sl_sys_id");

		var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('tasker_app_widget');
		data.appPreferences=taskWidgetIconsAndMessage.loadTaskerAppUserDefaults();

	}


})();
